/**
 * Arabic handwriting and display fonts sourced from Google Fonts.
 * These are loaded via the layout <link> tag and are available for use in
 * any custom UI within the Lawhaa application.
 *
 * Fonts:
 *   - Playpen Sans Arabic  (default Arabic UI font)
 *   - Noto Sans Arabic
 *   - IBM Plex Sans Arabic
 *   - Lalezar
 *   - Rakkas
 *   - Marhey
 */

export interface ArabicFont {
  id: string;
  name: string;
  cssFamily: string;
  /** Google Fonts URL query param value */
  googleParam: string;
}

export const ARABIC_FONTS: ArabicFont[] = [
  {
    id: "playpen-sans-arabic",
    name: "Playpen Sans Arabic",
    cssFamily: "'Playpen Sans Arabic', cursive",
    googleParam: "Playpen+Sans+Arabic:wght@400;700",
  },
  {
    id: "noto-sans-arabic",
    name: "Noto Sans Arabic",
    cssFamily: "'Noto Sans Arabic', sans-serif",
    googleParam: "Noto+Sans+Arabic:wght@400;700",
  },
  {
    id: "ibm-plex-sans-arabic",
    name: "IBM Plex Sans Arabic",
    cssFamily: "'IBM Plex Sans Arabic', sans-serif",
    googleParam: "IBM+Plex+Sans+Arabic:wght@400;700",
  },
  {
    id: "lalezar",
    name: "Lalezar",
    cssFamily: "'Lalezar', cursive",
    googleParam: "Lalezar",
  },
  {
    id: "rakkas",
    name: "Rakkas",
    cssFamily: "'Rakkas', cursive",
    googleParam: "Rakkas",
  },
  {
    id: "marhey",
    name: "Marhey",
    cssFamily: "'Marhey', cursive",
    googleParam: "Marhey:wght@400;700",
  },
];

/**
 * Build the Google Fonts <link> href that loads all Arabic fonts at once.
 */
export function buildGoogleFontsUrl(): string {
  const families = ARABIC_FONTS.map((f) => `family=${f.googleParam}`).join(
    "&"
  );
  return `https://fonts.googleapis.com/css2?${families}&display=swap`;
}
